<?php
if (!function_exists('hr_t')) {
  function hr_t($key, $fallback = '') { return lang_text($key, $fallback); }
}
if (!function_exists('hr_h')) {
  function hr_h($key, $fallback = '') { return htmlspecialchars((string) hr_t($key, $fallback), ENT_QUOTES, 'UTF-8'); }
}
if (!function_exists('hr_js')) {
  function hr_js($key, $fallback = '') { return json_encode(hr_t($key, $fallback), JSON_HEX_TAG | JSON_HEX_APOS | JSON_HEX_AMP | JSON_HEX_QUOT); }
}
if(session_status()===PHP_SESSION_NONE)session_start();include "../../inc/config.php";session_check_json();
function mm_json($s,$m='',$x=array()){header('Content-Type: application/json; charset=utf-8');$p=array('status'=>$s);if($m!=='')$p[$s==='good'?'message':'error_message']=$m;foreach($x as $k=>$v)$p[$k]=$v;echo json_encode($p);exit;}
function mm_h($v){return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');} function mm_p($k,$d=''){return isset($_POST[$k])?$_POST[$k]:$d;} function mm_c($v){return strtoupper(trim((string)$v));}
function mm_select2($rows,$id,$cb){$r=array();foreach($rows as $x)$r[]=array('id'=>$x->$id,'text'=>$cb($x));header('Content-Type: application/json');echo json_encode(array('results'=>$r));exit;}
function mm_no(){global $db;$prefix='EMM'.date('Ym');$r=$db->fetch("SELECT mutation_no FROM erp_employee_mutation WHERE mutation_no LIKE ? ORDER BY mutation_no DESC LIMIT 1",array($prefix.'%'));$n=$r?((int)substr($r->mutation_no,-4)+1):1;return $prefix.sprintf('%04d',$n);}
function emp($id){global $db;return $db->fetch("SELECT e.*,d.nm_dept,j.job_title_code,j.job_title_name,cs.structure_code,cs.structure_name,cc.cost_center_name,pc.profit_center_name FROM erp_employee_master e LEFT JOIN dept d ON d.kd_dept=e.department_code LEFT JOIN erp_job_title j ON j.id=e.job_title_id LEFT JOIN erp_company_structure cs ON cs.id=e.company_structure_id LEFT JOIN erp_cost_center cc ON cc.cost_center_code=e.cost_center_code LEFT JOIN erp_profit_center pc ON pc.profit_center_code=e.profit_center_code WHERE e.id=? LIMIT 1",array((int)$id));}
$act=isset($_GET['act'])?$_GET['act']:'';$user=isset($_SESSION['username'])?$_SESSION['username']:'admin';
switch($act){
case 'employee_search':$t=trim(mm_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,employee_no,full_name FROM erp_employee_master WHERE employment_status IN ('ACTIVE','PROBATION','CONTRACT') AND (?='' OR employee_no LIKE ? OR full_name LIKE ?) ORDER BY employee_no LIMIT 30",array($t,$like,$like));mm_select2($rows,'id',function($r){return $r->employee_no.' - '.$r->full_name;});
case 'department_search':$t=trim(mm_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT kd_dept,nm_dept,dept_type FROM dept WHERE status='ACTIVE' AND (?='' OR kd_dept LIKE ? OR nm_dept LIKE ?) ORDER BY kd_dept LIMIT 30",array($t,$like,$like));mm_select2($rows,'kd_dept',function($r){return $r->kd_dept.' - '.$r->nm_dept.' ['.$r->dept_type.']';});
case 'job_title_search':$t=trim(mm_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,job_title_code,job_title_name,job_level FROM erp_job_title WHERE status='ACTIVE' AND (?='' OR job_title_code LIKE ? OR job_title_name LIKE ?) ORDER BY job_level DESC,job_title_code LIMIT 30",array($t,$like,$like));mm_select2($rows,'id',function($r){return $r->job_title_code.' - '.$r->job_title_name.' ['.$r->job_level.']';});
case 'company_structure_search':$t=trim(mm_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT id,structure_code,structure_name,structure_type FROM erp_company_structure WHERE status='ACTIVE' AND structure_type IN ('ORG_UNIT','PERSONNEL_SUBAREA','PERSONNEL_AREA') AND (?='' OR structure_code LIKE ? OR structure_name LIKE ?) ORDER BY structure_code LIMIT 30",array($t,$like,$like));mm_select2($rows,'id',function($r){return $r->structure_code.' - '.$r->structure_name.' ['.$r->structure_type.']';});
case 'cost_center_search':$t=trim(mm_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT cost_center_code,cost_center_name FROM erp_cost_center WHERE status='Aktif' AND (?='' OR cost_center_code LIKE ? OR cost_center_name LIKE ?) ORDER BY cost_center_code LIMIT 30",array($t,$like,$like));mm_select2($rows,'cost_center_code',function($r){return $r->cost_center_code.' - '.$r->cost_center_name;});
case 'profit_center_search':$t=trim(mm_p('term'));$like='%'.$t.'%';$rows=$db->query("SELECT profit_center_code,profit_center_name FROM erp_profit_center WHERE status='Aktif' AND (?='' OR profit_center_code LIKE ? OR profit_center_name LIKE ?) ORDER BY profit_center_code LIMIT 30",array($t,$like,$like));mm_select2($rows,'profit_center_code',function($r){return $r->profit_center_code.' - '.$r->profit_center_name;});
case 'employee_snapshot':$e=emp((int)mm_p('employee_id'));if(!$e)mm_json('error','Employee tidak ditemukan.');mm_json('good','',array('data'=>(array)$e));
case 'get':$id=(int)mm_p('id');$r=$db->fetch("SELECT * FROM erp_employee_mutation WHERE id=? LIMIT 1",array($id));if(!$r)mm_json('error','Mutation tidak ditemukan.');mm_json('good','',array('data'=>(array)$r));
case 'save':
 $id=(int)mm_p('id');$eid=(int)mm_p('employee_id');$e=emp($eid);if(!$e)mm_json('error','Employee wajib dipilih.');
 $type=mm_c(mm_p('mutation_type','TRANSFER'));if(!in_array($type,array('TRANSFER','PROMOTION','DEMOTION','JOB_CHANGE','DEPARTMENT_CHANGE','COST_CENTER_CHANGE','STATUS_CHANGE','PAYROLL_CHANGE'),true))mm_json('error','Mutation Type tidak valid.');
 $mdate=trim(mm_p('mutation_date'));$edate=trim(mm_p('effective_date'));if($mdate===''||$edate==='')mm_json('error','Mutation Date dan Effective Date wajib diisi.');
 $data=array('mutation_no'=>trim(mm_p('mutation_no'))?:mm_no(),'mutation_date'=>$mdate,'effective_date'=>$edate,'employee_id'=>$eid,'mutation_type'=>$type,'reason_code'=>mm_c(mm_p('reason_code')),'reason_text'=>trim(mm_p('reason_text')),
 'old_department_code'=>$e->department_code,'new_department_code'=>mm_c(mm_p('new_department_code'))?:$e->department_code,'old_job_title_id'=>$e->job_title_id,'new_job_title_id'=>mm_p('new_job_title_id')!==''?(int)mm_p('new_job_title_id'):$e->job_title_id,'old_company_structure_id'=>$e->company_structure_id,'new_company_structure_id'=>mm_p('new_company_structure_id')!==''?(int)mm_p('new_company_structure_id'):$e->company_structure_id,'old_manager_employee_id'=>$e->manager_employee_id,'new_manager_employee_id'=>mm_p('new_manager_employee_id')!==''?(int)mm_p('new_manager_employee_id'):$e->manager_employee_id,'old_cost_center_code'=>$e->cost_center_code,'new_cost_center_code'=>trim(mm_p('new_cost_center_code'))?:$e->cost_center_code,'old_profit_center_code'=>$e->profit_center_code,'new_profit_center_code'=>trim(mm_p('new_profit_center_code'))?:$e->profit_center_code,'old_employee_group'=>$e->employee_group,'new_employee_group'=>mm_c(mm_p('new_employee_group'))?:$e->employee_group,'old_employee_subgroup'=>$e->employee_subgroup,'new_employee_subgroup'=>trim(mm_p('new_employee_subgroup'))?:$e->employee_subgroup,'old_payroll_area'=>$e->payroll_area,'new_payroll_area'=>trim(mm_p('new_payroll_area'))?:$e->payroll_area,'old_pay_grade'=>$e->pay_grade,'new_pay_grade'=>trim(mm_p('new_pay_grade'))?:$e->pay_grade,'old_work_location_type'=>$e->work_location_type,'new_work_location_type'=>mm_c(mm_p('new_work_location_type'))?:$e->work_location_type,'old_shift_code'=>$e->shift_code,'new_shift_code'=>trim(mm_p('new_shift_code'))?:$e->shift_code,'approval_status'=>mm_c(mm_p('approval_status','DRAFT')),'remarks'=>trim(mm_p('remarks')),'updated_by'=>$user,'updated_at'=>date('Y-m-d H:i:s'));
 if(!in_array($data['approval_status'],array('DRAFT','SUBMITTED','APPROVED','REJECTED','POSTED','CANCELLED'),true))mm_json('error','Approval Status tidak valid.');
 if($id>0){$old=$db->fetch("SELECT approval_status FROM erp_employee_mutation WHERE id=? LIMIT 1",array($id));if(!$old)mm_json('error','Mutation tidak ditemukan.');if($old->approval_status==='POSTED')mm_json('error','Mutation POSTED tidak bisa diedit.');$ok=$db->update('erp_employee_mutation',$data,'id',$id);}else{$data['created_by']=$user;$ok=$db->insert('erp_employee_mutation',$data);$id=$db->last_insert_id();}
 if(!$ok)mm_json('error',$db->getErrorMessage()?:'Mutation gagal disimpan.');mm_json('good','Employee Mutation berhasil disimpan.',array('id'=>$id));
case 'post':
 $id=(int)mm_p('id');$r=$db->fetch("SELECT * FROM erp_employee_mutation WHERE id=? LIMIT 1",array($id));if(!$r)mm_json('error','Mutation tidak ditemukan.');if(!in_array($r->approval_status,array('APPROVED','SUBMITTED'),true))mm_json('error','Hanya SUBMITTED/APPROVED yang bisa posting.');$update=array('department_code'=>$r->new_department_code,'job_title_id'=>$r->new_job_title_id,'company_structure_id'=>$r->new_company_structure_id,'manager_employee_id'=>$r->new_manager_employee_id,'cost_center_code'=>$r->new_cost_center_code,'profit_center_code'=>$r->new_profit_center_code,'employee_group'=>$r->new_employee_group,'employee_subgroup'=>$r->new_employee_subgroup,'payroll_area'=>$r->new_payroll_area,'pay_grade'=>$r->new_pay_grade,'work_location_type'=>$r->new_work_location_type,'shift_code'=>$r->new_shift_code,'updated_by'=>$user,'updated_at'=>date('Y-m-d H:i:s'));$db->update('erp_employee_master',$update,'id',$r->employee_id);$db->update('erp_employee_mutation',array('approval_status'=>'POSTED','approved_by'=>$r->approved_by?:$user,'approved_at'=>$r->approved_at?:date('Y-m-d H:i:s'),'posted_by'=>$user,'posted_at'=>date('Y-m-d H:i:s'),'updated_by'=>$user,'updated_at'=>date('Y-m-d H:i:s')),'id',$id);mm_json('good','Mutation berhasil diposting ke Employee Master.');
case 'delete':$id=(int)mm_p('id');$r=$db->fetch("SELECT approval_status FROM erp_employee_mutation WHERE id=? LIMIT 1",array($id));if(!$r)mm_json('error','Mutation tidak ditemukan.');if($r->approval_status==='POSTED')mm_json('error','Mutation POSTED tidak bisa dihapus.');$db->delete('erp_employee_mutation','id',$id);mm_json('good','Mutation berhasil dihapus.');
case 'detail':$id=(int)mm_p('id');$r=$db->fetch("SELECT m.*,e.employee_no,e.full_name FROM erp_employee_mutation m JOIN erp_employee_master e ON e.id=m.employee_id WHERE m.id=? LIMIT 1",array($id));if(!$r){echo '<div class=\"alert alert-warning\">Mutation tidak ditemukan.</div>';break;}echo '<h3 style=\"margin-top:0\">'.mm_h($r->mutation_no).' <small>'.mm_h($r->employee_no.' - '.$r->full_name).'</small></h3><span class=\"label label-info\">'.mm_h($r->mutation_type).'</span> <span class=\"label label-success\">'.mm_h($r->approval_status).'</span><hr>';echo '<div class=\"row\"><div class=\"col-sm-3\"><b>Mutation Date</b><br>'.mm_h($r->mutation_date).'</div><div class=\"col-sm-3\"><b>Effective</b><br>'.mm_h($r->effective_date).'</div><div class=\"col-sm-3\"><b>Created</b><br>'.mm_h($r->created_by).'</div><div class=\"col-sm-3\"><b>Updated</b><br>'.mm_h($r->updated_by?:'-').'</div></div><hr>';echo '<table class=\"table table-bordered\"><tr><th>Field</th><th>Before</th><th>After</th></tr><tr><td>'.hr_h('hr_department', 'Department').'</td><td>'.mm_h($r->old_department_code).'</td><td>'.mm_h($r->new_department_code).'</td></tr><tr><td>'.hr_h('hr_job_title', 'Job Title').'</td><td>'.mm_h($r->old_job_title_id).'</td><td>'.mm_h($r->new_job_title_id).'</td></tr><tr><td>Cost Center</td><td>'.mm_h($r->old_cost_center_code).'</td><td>'.mm_h($r->new_cost_center_code).'</td></tr><tr><td>Pay Grade</td><td>'.mm_h($r->old_pay_grade).'</td><td>'.mm_h($r->new_pay_grade).'</td></tr></table><b>Reason</b><p>'.mm_h($r->reason_text?:'-').'</p>';
default:mm_json('error','Action tidak dikenal.');
}
?>
